import React from 'react'
import { Parallax } from 'react-parallax'
import { motion,useViewportScroll, useTransform } from "framer-motion";
import '../Header/header.scss'

const Header = () => {

    const navVariantsY = {
        hidden: {
            opacity: 1,
            y: 100,
            transition: {
                type: 'spring',
                stiffness: 300,
                damping: 140,
            },
        },
        show: {
            opacity: 1,
            y: 0,
            transition: {
                type: 'spring',
                stiffness: 80,
                delay: 0.1,
            },
        },
    };

    const { scrollYProgress } = useViewportScroll();
    const scale = useTransform(scrollYProgress,[0, 0], [0, 0]);

    return (
        <div id='home' className='header'>
            <Parallax bgImage="../../img/header-mob1.png"  bgClassName='parallax' bgImageAlt="the cat" strength={50}>
                <motion.div variants={navVariantsY} initial="hidden" whileInView="show" style={{scale}} className='header__img' >
                    <motion.div className='header__img--logo'/>
                </motion.div>
            </Parallax>
        </div>
    )
}

export default Header
